              onDoubleTap: () => setState(() {
                _top = 200; _left = 100; _hue = 0;
              }),
              child: Container(
                width: 80, height: 80,
                decoration: BoxDecoration(
                  color: color,
                  shape: BoxShape.circle,
                  boxShadow: const [BoxShadow(blurRadius: 12, color: Colors.black26)],
