import 'package:flutter/services.dart';

TextFormField(
  keyboardType: TextInputType.phone,
  inputFormatters: [
    FilteringTextInputFormatter.digitsOnly,   // 숫자만 허용
    LengthLimitingTextInputFormatter(11),      // 최대 11자
    _PhoneNumberFormatter(),                   // 하이픈 자동 삽입
  ],
