class _TimerPageState extends State<TimerPage> {
  bool _running = false;
  Stream<int>? _timerStream;
  int _elapsed = 0;

  Stream<int> _buildStream() async* {
    while (_running) {
      yield _elapsed++;
      await Future.delayed(const Duration(seconds: 1));
    }
  }

  void _start() {
    setState(() {
      _running = true;
      _timerStream = _buildStream();
    });
  }

  void _pause() => setState(() => _running = false);

  void _reset() {
    setState(() {
      _running = false;
      _elapsed = 0;
      _timerStream = null;
    });
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('타이머')),
      body: Center(
        child: Column(
          mainAxisAlignment: MainAxisAlignment.center,
          children: [
            StreamBuilder<int>(
              stream: _timerStream ?? const Stream.empty(),
              initialData: _elapsed,
              builder: (context, snapshot) {
                final secs = snapshot.data ?? 0;
                final m = secs ~/ 60;
                final s = secs % 60;
                return Text(
                  '${m.toString().padLeft(2, '0')}:${s.toString().padLeft(2, '0')}',
                  style: const TextStyle(
                      fontSize: 72, fontWeight: FontWeight.bold,
                      fontFeatures: [FontFeature.tabularFigures()]),
                );
              },
            ),
            const SizedBox(height: 32),
            Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                FilledButton(
                  onPressed: _running ? _pause : _start,
                  child: Text(_running ? '일시정지' : '시작'),
                ),
                const SizedBox(width: 12),
                OutlinedButton(
                  onPressed: _reset,
                  child: const Text('리셋'),
                ),
              ],
            ),
          ],
        ),
      ),
    );
  }
}

