      appBar: AppBar(
        title: const Text('JSONPlaceholder Posts'),
        actions: [
          IconButton(
            icon: const Icon(Icons.add),
            onPressed: _createPost,
          ),
          IconButton(
            icon: const Icon(Icons.refresh),
            onPressed: () => setState(() {
              _postsFuture = _repo.getPosts();
