class DatabaseHelper {
  static Database? _database;

  static Future<Database> get database async {
    _database ??= await _initDatabase();
    return _database!;
  }

  static Future<Database> _initDatabase() async {
    final path = join(await getDatabasesPath(), 'app.db');
    return openDatabase(
      path,
      version: 1,
      onCreate: _onCreate,
      onUpgrade: _onUpgrade,
    );
  }

  static Future<void> _onCreate(Database db, int version) async {
    await db.execute('''
      CREATE TABLE products (
        id       INTEGER PRIMARY KEY AUTOINCREMENT,
        name     TEXT    NOT NULL,
        price    REAL    NOT NULL,
        category TEXT,
        created_at TEXT DEFAULT CURRENT_TIMESTAMP
      )
    ''');
    await db.execute('''
      CREATE TABLE cart_items (
        id         INTEGER PRIMARY KEY AUTOINCREMENT,
        product_id INTEGER REFERENCES products(id) ON DELETE CASCADE,
        quantity   INTEGER NOT NULL DEFAULT 1
      )
    ''');
  }

  // 스키마 변경 시 (앱 업데이트)
  static Future<void> _onUpgrade(Database db, int oldV, int newV) async {
    if (oldV < 2) {
      await db.execute('ALTER TABLE products ADD COLUMN rating REAL DEFAULT 0');
    }
  }
}

// Repository
class ProductSqlRepository {
  Future<Database> get _db => DatabaseHelper.database;

  // 전체 조회
  Future<List<Product>> getAll({String? category}) async {
    final db = await _db;
    final maps = await db.query(
      'products',
      where: category != null ? 'category = ?' : null,
      whereArgs: category != null ? [category] : null,
      orderBy: 'created_at DESC',
    );
    return maps.map(Product.fromMap).toList();
  }

  // 검색
  Future<List<Product>> search(String keyword) async {
    final db = await _db;
    final maps = await db.rawQuery('''
      SELECT * FROM products
      WHERE name LIKE ? OR category LIKE ?
      ORDER BY name ASC
    ''', ['%$keyword%', '%$keyword%']);
    return maps.map(Product.fromMap).toList();
  }

  // 추가
  Future<int> insert(Product product) async {
    final db = await _db;
    return db.insert('products', product.toMap());
  }

  // 수정
  Future<int> update(Product product) async {
    final db = await _db;
    return db.update(
      'products',
      product.toMap(),
      where: 'id = ?',
      whereArgs: [product.id],
    );
  }

  // 삭제
  Future<int> delete(int id) async {
    final db = await _db;
    return db.delete('products', where: 'id = ?', whereArgs: [id]);
  }

  // 트랜잭션
  Future<void> transferStock(int fromId, int toId, int quantity) async {
    final db = await _db;
    await db.transaction((txn) async {
      await txn.rawUpdate(
        'UPDATE products SET stock = stock - ? WHERE id = ?',
        [quantity, fromId],
      );
      await txn.rawUpdate(
        'UPDATE products SET stock = stock + ? WHERE id = ?',
        [quantity, toId],
      );
    });
  }
}

