class SlowMiddleCurve extends Curve {
  @override
  double transform(double t) {
    // t: 0.0 ~ 1.0
    // 가운데 구간을 느리게
    if (t < 0.5) return t * 0.5;
    return 0.25 + (t - 0.5) * 1.5;
  }
}

