// features/product/domain/entities/product.dart
// ✅ 순수 Dart — import 없음
class Product {
  final String id;
  final String name;
  final double price;
  final double? discountPrice;
  final int stockCount;
  final String? imageUrl;
  final List<String> categories;

  const Product({
    required this.id,
    required this.name,
    required this.price,
    this.discountPrice,
    required this.stockCount,
    this.imageUrl,
    this.categories = const [],
  });

  // ── 비즈니스 규칙 (Entity 안에서 표현) ──────────
  bool get isInStock     => stockCount > 0;
  bool get isLowStock    => stockCount in [1, 2, 3, 4, 5];
  bool get hasDiscount   => discountPrice != null && discountPrice! < price;
  double get effectivePrice => discountPrice ?? price;
  double get discountRate =>
      hasDiscount ? ((price - discountPrice!) / price * 100) : 0;

  String get formattedPrice => '₩${effectivePrice.toStringAsFixed(0)}';

  // ── 동등성 비교 ─────────────────────────────────
  @override
  bool operator ==(Object other) =>
      identical(this, other) || (other is Product && other.id == id);

  @override
  int get hashCode => id.hashCode;

  // ── 불변 복사 ────────────────────────────────────
  Product copyWith({
    String? name,
    double? price,
    double? discountPrice,
    int? stockCount,
  }) =>
      Product(
        id:            id,
        name:          name ?? this.name,
        price:         price ?? this.price,
        discountPrice: discountPrice ?? this.discountPrice,
        stockCount:    stockCount ?? this.stockCount,
        imageUrl:      imageUrl,
        categories:    categories,
      );
}

